def main():
    """Main entry point for the circopt CLI."""
    # Check for --version
    if '--version' in sys.argv:
        json_flag = '--json' in sys.argv
        return handle_version(json_flag)

    # Parse command
    args = sys.argv[1:]

    if len(args) == 0:
        print("Error: No command specified")
        print("Usage: python circopt.py <command> [options]")
        print("Commands: check, eval")
        return 1

    command = args[0]

    if command == 'check':
        json_flag = '--json' in args
        # Find the filename
        filename = None
        for arg in args[1:]:
            if arg != '--json':
                filename = arg
                break

        if filename is None:
            print("Error: Missing required argument: <file.circ>")
            return 1

        return handle_check(filename, json_flag, "check")

    elif command == 'eval':
        json_flag = '--json' in args

        # Parse --radix and --mode options
        radix = "bin"  # default
        mode = "2val"  # default
        radix_idx = -1
        mode_idx = -1
        for i, arg in enumerate(args):
            if arg == '--radix':
                radix_idx = i
            elif arg == '--mode':
                mode_idx = i
        if radix_idx >= 1 and radix_idx + 1 < len(args):
            radix_val = args[radix_idx + 1]
            if radix_val in ('bin', 'hex', 'dec'):
                radix = radix_val
            else:
                print(f"Error: Invalid radix '{radix_val}' (must be bin, hex, or dec)")
                return 1

        if mode_idx >= 1 and mode_idx + 1 < len(args):
            mode_val = args[mode_idx + 1]
            if mode_val in ('2val', '3val'):
                mode = mode_val
            else:
                print(f"Error: Invalid mode '{mode_val}' (must be 2val or 3val)")
                return 1

        # Parse other options
        set_inputs: list[str] = []
        default = 0
        allow_extra = False
        filepath = None

        i = 1
        while i < len(args):
            arg = args[i]
            if arg in ('--radix', '--mode'):
                i += 2
                continue
            elif arg == '--set':
                if i + 1 < len(args):
                    set_inputs.append(args[i + 1])
                    i += 2
                else:
                    print("Error: Missing value for --set")
                    return 1
            elif arg == '--default':
                if i + 1 < len(args):
                    try:
                        default = int(args[i + 1])
                        if default not in (0, 1):
                            print(f"Error: --default must be 0 or 1, got '{args[i + 1]}'")
                            return 2
                    except ValueError:
                        print(f"Error: --default must be an integer, got '{args[i + 1]}'")
                        return 2
                    i += 2
                else:
                    print("Error: Missing value for --default")
                    return 1
            elif arg == '--allow-extra':
                allow_extra = True
                i += 1
            elif arg == '--json':
                i += 1
            else:
                filepath = arg
                break

        if filepath is None:
            print("Error: Missing required argument: <file.circ>")
            return 1

        # Check for radix restriction in 3val mode
        if mode == "3val" and radix in ('hex', 'dec'):
            if json_flag:
                error = RadixNotAllowedIn3ValError()
                print(json.dumps(error.to_json("eval", filepath)))
            else:
                print(f"Error: {RadixNotAllowedIn3ValError()}")
            return 1

        return handle_eval(filepath, set_inputs, default, allow_extra, json_flag, "eval", radix, mode)

    else:
        print(f"Error: Unknown command '{command}'")
        return 1


if __name__ == '__main__':
    sys.exit(main())

